3. **Implement ETag Support for Conflict Resolution**:
```typescript
// services/api/dotypos.service.ts
export class DotyposApiService {
  // ... existing code

  private etags: Map<string, string> = new Map();

  // Store ETag after successful request
  private storeETag(resourceId: string, etag: string): void {
    this.etags.set(resourceId, etag);
  }

  // Get ETag for a resource if available
  private getETag(resourceId: string): string | undefined {
    return this.etags.get(resourceId);
  }

  // Example of using ETag in update request
  async updateReservation(cloudId: string, reservationId: string, data: Partial<ReservationCreateRequest>): Promise<ReservationResponse> {
    const endpoint = `${this.getReservationsEndpoint(cloudId)}/${reservationId}`;
    const etag = this.getETag(reservationId);

    const headers: HeadersInit = {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${await this.authService.getAccessToken()}`
    };

    // Add If-Match header if we have an ETag
    if (etag) {
      headers['If-Match'] = etag;
    }

    const response = await fetch(endpoint, {
      method: 'PATCH',
      headers,
      body: JSON.stringify(data)
    });

    if (response.status === 412) {
      throw new Error('Precondition Failed: The resource has been modified by another request');
    }

    if (!response.ok) {
      throw new Error(`Failed to update reservation: ${response.statusText}`);
    }

    // Store new ETag if provided
    const newETag = response.headers.get('ETag');
    if (newETag) {
      this.storeETag(reservationId, newETag);
    }

    return await response.json();
  }
}
```

4. **Integrate with Authentication Service**:
```typescript
// services/api/dotypos.service.ts
export class DotyposApiService {
  // ... existing code

  async getReservations(cloudId: string, params?: { 
    startDate?: string, 
    endDate?: string,
    tableId?: string
  }): Promise<ReservationResponse[]> {
    const endpoint = this.getReservationsEndpoint(cloudId);
    const queryParams = new URLSearchParams();

    if (params?.startDate) queryParams.append('startDate', params.startDate);
    if (params?.endDate) queryParams.append('endDate', params.endDate);
    if (params?.tableId) queryParams.append('tableId', params.tableId);

    const queryString = queryParams.toString();
    const url = queryString ? `${endpoint}?${queryString}` : endpoint;

    try {
      // Get token from auth service
      const token = await this.authService.getAccessToken();

      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch reservations: ${response.statusText}`);
      }

      // Store ETag if provided
      const etag = response.headers.get('ETag');
      if (etag) {
        this.storeETag(`reservations-${cloudId}`, etag);
      }

      return await response.json();
    } catch (error) {
      // Handle authentication errors specifically
      if (error instanceof Error && error.message.includes('authentication')) {
        // Attempt to refresh token and retry once
        await this.authService.refreshToken();
        return this.getReservations(cloudId, params);
      }
      throw error;
    }
  }
}
```

5. **Implement Error Handling and Retry Logic**:
```typescript
// services/api/dotypos.service.ts
export class DotyposApiService {
  // ... existing code

  private async executeRequest<T>(
    url: string, 
    method: string, 
    body?: any, 
    etag?: string
  ): Promise<T> {
    const headers: HeadersInit = {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${await this.authService.getAccessToken()}`
    };

    if (etag) {
      headers['If-Match'] = etag;
    }

    try {
      const response = await fetch(url, {
        method,
        headers,
        body: body ? JSON.stringify(body) : undefined
      });

      // Handle different response statuses
      if (response.status === 401) {
        // Token expired, refresh and retry
        await this.authService.refreshToken();
        return this.executeRequest(url, method, body, etag);
      }

      if (response.status === 412) {
        throw new Error('PRECONDITION_FAILED');
      }

      if (!response.ok) {
        throw new Error(`API request failed: ${response.statusText}`);
      }

      // Store ETag if available
      const newETag = response.headers.get('ETag');
      if (newETag && url.includes('/')) {
        const resourceId = url.split('/').pop() || '';
        this.storeETag(resourceId, newETag);
      }

      return await response.json();
    } catch (error) {
      // Log error and rethrow
      console.error('API request failed:', error);
      throw error;
    }
  }
}
```

