    return this.executeRequest<ReservationResponse>(endpoint, 'PATCH', data, etag);
  }

  // Delete reservation
  async deleteReservation(cloudId: string, reservationId: string): Promise<void> {
    const endpoint = `${this.getReservationsEndpoint(cloudId)}/${reservationId}`;
    const etag = this.getETag(reservationId);
