## Objective
Implement a robust phone number normalization system that ensures consistent formatting, validation, and display of phone numbers throughout the application while maintaining compatibility with Dotypos API requirements.

## Implementation Steps

1. **Create Phone Number Utility Module**:
```typescript
// lib/utils/phone-number.ts
import { parsePhoneNumber, isValidPhoneNumber, formatPhoneNumber } from 'libphonenumber-js';

/**
 * Normalizes a phone number to E.164 format
 * @param phoneNumber The phone number to normalize
 * @param defaultCountry The default country code to use if not specified in the number
 * @returns The normalized phone number in E.164 format or null if invalid
 */
export function normalizePhoneNumber(phoneNumber: string, defaultCountry = 'CZ'): string | null {
  if (!phoneNumber) return null;

  try {
    // Clean the input (remove spaces, dashes, parentheses)
    const cleaned = phoneNumber.replace(/[\s\-\(\)]/g, '');

    // Parse the phone number
    const parsed = parsePhoneNumber(cleaned, defaultCountry);

    // Return in E.164 format if valid
    if (parsed && parsed.isValid()) {
      return parsed.format('E.164');
    }

    return null;
  } catch (error) {
    console.error('Error normalizing phone number:', error);
    return null;
  }
}

/**
 * Validates a phone number
 * @param phoneNumber The phone number to validate
 * @param defaultCountry The default country code to use if not specified
 * @returns Boolean indicating if the phone number is valid
 */
export function validatePhoneNumber(phoneNumber: string, defaultCountry = 'CZ'): boolean {
  if (!phoneNumber) return false;

  try {
    return isValidPhoneNumber(phoneNumber, defaultCountry);
  } catch (error) {
    return false;
  }
}

/**
 * Formats a phone number for display
 * @param phoneNumber The E.164 formatted phone number
 * @param format The desired format ('NATIONAL' or 'INTERNATIONAL')
 * @returns Formatted phone number for display
 */
export function formatPhoneNumberForDisplay(phoneNumber: string, format: 'NATIONAL' | 'INTERNATIONAL' = 'NATIONAL'): string {
  if (!phoneNumber) return '';

  try {
    const parsed = parsePhoneNumber(phoneNumber);
    if (parsed && parsed.isValid()) {
      return parsed.format(format);
    }
    return phoneNumber;
  } catch (error) {
    return phoneNumber;
  }
}
```

2. **Create a Custom Phone Input Component**:
```tsx
// components/ui/phone-input.tsx
import React, { useState, useEffect } from 'react';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { normalizePhoneNumber, validatePhoneNumber, formatPhoneNumberForDisplay } from '@/lib/utils/phone-number';
import { cn } from '@/lib/utils';

interface PhoneInputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  error?: string;
  defaultCountry?: string;
  onPhoneChange?: (normalizedPhone: string | null) => void;
}

export function PhoneInput({
  label,
  error,
  defaultCountry = 'CZ',
  className,
  value,
  onChange,
  onPhoneChange,
  ...props
}: PhoneInputProps) {
  const [inputValue, setInputValue] = useState<string>(value as string || '');
  const [isValid, setIsValid] = useState<boolean>(true);
  const [displayValue, setDisplayValue] = useState<string>('');

  // Handle input changes
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    setInputValue(newValue);

    // Call the original onChange if provided
    if (onChange) {
      onChange(e);
    }

    // Validate and normalize the phone number
    const isValidPhone = validatePhoneNumber(newValue, defaultCountry);
    setIsValid(isValidPhone || newValue === '');

    // Normalize and pass to parent if valid
    const normalized = normalizePhoneNumber(newValue, defaultCountry);
    if (onPhoneChange) {
      onPhoneChange(normalized);
    }
  };

  // Format for display when focus is lost
  const handleBlur = () => {
    if (inputValue && isValid) {
      const normalized = normalizePhoneNumber(inputValue, defaultCountry);
      if (normalized) {
        const formatted = formatPhoneNumberForDisplay(normalized);
        setDisplayValue(formatted);
      }
    }
  };

  // Show raw input when focused
  const handleFocus = () => {
    setDisplayValue(inputValue);
  };

  return (
    <div className="space-y-2">
      {label && <Label htmlFor={props.id}>{label}</Label>}
      <Input
        {...props}
        type="tel"
        value={displayValue || inputValue}
        onChange={handleChange}
        onBlur={handleBlur}
        onFocus={handleFocus}
        className={cn(
          className,
          !isValid && inputValue !== '' ? 'border-red-500 focus-visible:ring-red-500' : ''
        )}
      />
      {error && <p className="text-sm text-red-500">{error}</p>}
      {!isValid && inputValue !== '' && !error && (
        <p className="text-sm text-red-500">Please enter a valid phone number</p>
      )}
    </div>
  );
}
```

