7. **Create Migration Script for Existing Data**:
```typescript
// scripts/migrate-phone-numbers.ts
import { db } from '@/lib/db';
import { normalizePhoneNumber } from '@/lib/utils/phone-number';

async function migratePhoneNumbers() {
  console.log('Starting phone number migration...');

  // Get all users with phone numbers
  const users = await db.user.findMany({
    where: {
      phoneNumber: {
        not: null,
      },
    },
  });

  console.log(`Found ${users.length} users with phone numbers to migrate`);

  // Update each user with normalized phone number
  let updated = 0;
  let skipped = 0;

  for (const user of users) {
    const normalized = normalizePhoneNumber(user.phoneNumber);

    if (normalized && normalized !== user.phoneNumber) {
      await db.user.update({
        where: { id: user.id },
        data: { phoneNumber: normalized },
      });
      updated++;
    } else {
      skipped++;
    }
  }

  console.log(`Migration complete: ${updated} updated, ${skipped} skipped`);
}

// Run the migration
migratePhoneNumbers()
  .then(() => process.exit(0))
  .catch((error) => {
    console.error('Migration failed:', error);
    process.exit(1);
  });
```

