   });

   // Create PDF Document component
   const MenuPDF = ({ categories }: { categories: MenuCategory[] }) => (
     <Document>
       <Page size="A4" style={styles.page}>
         {categories.map((category) => (
           <View key={category.id} style={styles.section}>
