## Objective
Implement a pagination system for the board games list to improve page load performance and enhance user experience by displaying games in manageable chunks.

## Implementation Steps

1. **Analyze Current Implementation**:
   - Review the existing `GamesGallery` component in the board games page
   - Identify how games data is currently loaded and rendered
   - Determine optimal page size (recommend 12-24 games per page)

2. **Update Data Fetching Logic**:
```typescript
// lib/games/games-service.ts
export interface GamesQueryParams {
  page?: number;
  pageSize?: number;
  category?: string;
}

export async function getGames(params: GamesQueryParams = {}) {
  const { page = 1, pageSize = 24, category } = params;

  // Fetch all games first (from API or local data)
  const allGames = await fetchAllGames();

  // Filter by category if needed
  const filteredGames = category 
    ? allGames.filter(game => game.categories.includes(category)) 
    : allGames;

  // Calculate pagination
  const totalGames = filteredGames.length;
  const totalPages = Math.ceil(totalGames / pageSize);
  const startIndex = (page - 1) * pageSize;
  const endIndex = startIndex + pageSize;

  // Return paginated result
  return {
    games: filteredGames.slice(startIndex, endIndex),
    pagination: {
      currentPage: page,
      totalPages,
      totalGames,
      hasNextPage: page < totalPages,
      hasPrevPage: page > 1
    }
  };
}
```

3. **Implement Pagination UI Component**:
```tsx
// components/ui/pagination.tsx
import { Button } from '@/components/ui/button';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { createTranslator } from '@/paraglide/runtime';

interface PaginationProps {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
  locale: string;
}

export function Pagination({ currentPage, totalPages, onPageChange, locale }: PaginationProps) {
  const t = createTranslator(locale);

  // Calculate which page numbers to show
  const getPageNumbers = () => {
    const pages = [];
    const maxVisiblePages = 5;

    if (totalPages <= maxVisiblePages) {
      // Show all pages if there are few
      for (let i = 1; i <= totalPages; i++) {
        pages.push(i);
      }
    } else {
      // Show pages around current page
      let startPage = Math.max(1, currentPage - 2);
      let endPage = Math.min(totalPages, startPage + maxVisiblePages - 1);

      if (endPage - startPage < maxVisiblePages - 1) {
        startPage = Math.max(1, endPage - maxVisiblePages + 1);
      }

      if (startPage > 1) {
        pages.push(1);
        if (startPage > 2) pages.push('ellipsis');
      }

      for (let i = startPage; i <= endPage; i++) {
        pages.push(i);
      }

      if (endPage < totalPages) {
        if (endPage < totalPages - 1) pages.push('ellipsis');
        pages.push(totalPages);
      }
    }

    return pages;
  };

  return (
    <nav className="flex items-center justify-center space-x-1 mt-8" aria-label={t('pagination.label')}>
      <Button
        variant="outline"
        size="icon"
        onClick={() => onPageChange(currentPage - 1)}
        disabled={currentPage === 1}
        aria-label={t('pagination.previous')}
      >
        <ChevronLeft className="h-4 w-4" />
      </Button>

      {getPageNumbers().map((page, index) => 
        page === 'ellipsis' ? (
          <span key={`ellipsis-${index}`} className="px-3 py-2">...</span>
        ) : (
          <Button
            key={`page-${page}`}
            variant={currentPage === page ? "default" : "outline"}
            size="sm"
            onClick={() => onPageChange(Number(page))}
            aria-current={currentPage === page ? "page" : undefined}
            aria-label={t('pagination.goToPage', { page })}
            className="min-w-[40px]"
          >
            {page}
          </Button>
        )
      )}

      <Button
        variant="outline"
        size="icon"
        onClick={() => onPageChange(currentPage + 1)}
        disabled={currentPage === totalPages}
        aria-label={t('pagination.next')}
      >
        <ChevronRight className="h-4 w-4" />
      </Button>
    </nav>
  );
}
```

4. **Update Games Gallery Component**:
```tsx
// components/games-gallery.tsx
import { useState, useEffect } from 'react';
import { useSearchParams, useRouter, usePathname } from 'next/navigation';
import { getGames } from '@/lib/games/games-service';
import { GameCard } from '@/components/game-card';
import { Pagination } from '@/components/ui/pagination';
import { createTranslator } from '@/paraglide/runtime';

interface GamesGalleryProps {
  locale: string;
}

export function GamesGallery({ locale }: GamesGalleryProps) {
  const t = createTranslator(locale);
  const searchParams = useSearchParams();
  const router = useRouter();
  const pathname = usePathname();

  // Get current page from URL or default to 1
  const currentPage = Number(searchParams.get('page') || 1);
  const currentCategory = searchParams.get('category') || '';

  const [gamesData, setGamesData] = useState({
    games: [],
    pagination: {
      currentPage: 1,
      totalPages: 1,
      totalGames: 0,
      hasNextPage: false,
      hasPrevPage: false
    },
    isLoading: true
  });

  // Fetch games when page or category changes
  useEffect(() => {
    const fetchGames = async () => {
      setGamesData(prev => ({ ...prev, isLoading: true }));

      try {
        const data = await getGames({
          page: currentPage,
          pageSize: 24,
          category: currentCategory || undefined
        });

        setGamesData({
          games: data.games,
          pagination: data.pagination,
          isLoading: false
        });
      } catch (error) {
        console.error('Failed to fetch games:', error);
        setGamesData(prev => ({ ...prev, isLoading: false }));
      }
    };

    fetchGames();
  }, [currentPage, currentCategory]);

  // Handle page change
  const handlePageChange = (page: number) => {
    const params = new URLSearchParams(searchParams);
    params.set('page', page.toString());
    router.push(`${pathname}?${params.toString()}`);

    // Scroll to top of games section
    document.getElementById('games-section')?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div id="games-section" className="w-full">
      {/* Category filters can go here */}

      {gamesData.isLoading ? (
        <div className="flex justify-center py-12">
          <LoadingSpinner />
        </div>
      ) : (
        <>
          <p className="text-sm text-muted-foreground mb-4">
            {t('games.showing')} {gamesData.pagination.totalGames} {t('games.total')}
          </p>

          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
            {gamesData.games.map(game => (
              <GameCard key={game.id} game={game} locale={locale} />
            ))}
          </div>

          {gamesData.pagination.totalPages > 1 && (
            <Pagination
              currentPage={gamesData.pagination.currentPage}
              totalPages={gamesData.pagination.totalPages}
              onPageChange={handlePageChange}
              locale={locale}
            />
          )}
        </>
      )}
    </div>
  );
}
```

